local LxBaseAdapter = require("LApp.adapter.LxBaseAdapter")
---@class LxLoginAdapter:LxBaseAdapter
local LxLoginAdapter = classX("LxLoginAdapter", LxBaseAdapter)

function LxLoginAdapter:Initialize()
    LxBaseAdapter.Initialize(self)
    self._adapterName = LevelNames.Login
end


function LxLoginAdapter:Dispose()
    gLGameLogin:OnDealSceneDestroy()
    LxBaseAdapter.Dispose(self)
end

function LxLoginAdapter:OnEnterLevel(scene, loadMode, mapGo)
    LxBaseAdapter.OnEnterLevel(self,scene, loadMode, mapGo)
    self:OnSceneEnterFinished()
end

function LxLoginAdapter:OnLeaveLevel()
    gLGameLogin:OnDealSceneDestroy()
end

function LxLoginAdapter:OnLevelLoaded()
    LxBaseAdapter.OnLevelLoaded(self)
    self:OnSceneLoaded()
end

function LxLoginAdapter:IsHideLoadingBg()
    return true
end

---@param batchTask LxPreloadTask
function LxLoginAdapter:AfterLevelLoaded(batchTask)


    gLGameLogin:SetSceneEnterCallBack(function()
        self:OnSceneEnter()
    end)

    batchTask:AddBatchTask("prepareLogin", "prepareLogin", self.PrepareScene, self)
end


function LxLoginAdapter:OnSceneLoaded()
    --if LGameSettings.isLoginAfter then
    --    gLxPatchCtrl:OnPrepareLevelOk()
    --else
        gLGameLogin:OnDealSceneLoaded()
    --end
end

function LxLoginAdapter:PrepareScene(actionOk, actionObj)
    self._actionOk = actionOk
    self._actionObj = actionObj

    if LGameSettings.isLoginAfter then
        gLGameLogin:OnScenePrepareOk()
    else
        gLGameLogin:OnDealScenePrepare()
    end
end

function LxLoginAdapter:OnSceneEnter()
    local actionOk = self._actionOk
    local actionObj = self._actionObj
    self._actionOk = nil
    self._actionObj = nil
    actionOk(actionObj)
end

function LxLoginAdapter:OnSceneEnterFinished()
    if LGameSettings.isLoginAfter then

        --处理完GameUpdate逻辑，这里直接让登录相关逻辑同时启动让它同步进行，跟服务器交互异步返回的处理已单独到一个函数
        gLGameLogin:OnDealSceneLoaded()
        gLGameLogin:OnDealSceneEnterFinished()
    else
        gLGameLogin:OnDealSceneEnterFinished()
    end
end

return LxLoginAdapter